import{_ as a,c as i,o as e,aN as l}from"./chunks/framework.BRm39z_l.js";const c=JSON.parse('{"title":"MyBatis基础","description":"","frontmatter":{},"headers":[],"relativePath":"middleware/02. MyBatis/01.MyBatis基础.md","filePath":"middleware/02. MyBatis/01.MyBatis基础.md"}'),t={name:"middleware/02. MyBatis/01.MyBatis基础.md"};function n(h,s,r,p,o,d){return e(),i("div",null,s[0]||(s[0]=[l('<h1 id="mybatis基础" tabindex="-1">MyBatis基础 <a class="header-anchor" href="#mybatis基础" aria-label="Permalink to &quot;MyBatis基础&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#什么是-mybatis">什么是 MyBatis</a><ul><li><a href="#orm-是什么">ORM 是什么</a></li><li><a href="#为什么说-mybatis-是半自动-orm-映射工具-它与全自动的区别在哪里">为什么说 Mybatis 是半自动 ORM 映射工具？它与全自动的区别在哪里？</a></li></ul></li><li><a href="#mybatis-使用过程">MyBatis 使用过程</a><ul><li><a href="#创建-sqlsessionfactory">创建 SqlSessionFactory</a></li><li><a href="#创建-sqlsession">创建 SqlSession</a></li><li><a href="#通过-sqlsession-执行数据库操作">通过 sqlsession 执行数据库操作</a></li></ul></li><li><a href="#和-的区别">#{}和${}的区别?</a></li><li><a href="#mybatis-的一级、二级缓存">Mybatis 的一级、二级缓存</a></li><li><a href="#如何防止-sql-住入">如何防止 sql 住入</a><ul><li><a href="#使用参数化查询">使用参数化查询</a></li><li><a href="#限制用户输入">限制用户输入</a></li><li><a href="#使用-orm-框架">使用 ORM 框架</a></li></ul></li></ul></nav><h2 id="什么是-mybatis" tabindex="-1">什么是 MyBatis <a class="header-anchor" href="#什么是-mybatis" aria-label="Permalink to &quot;什么是 MyBatis&quot;">​</a></h2><p>Mybatis 是一个半 ORM 框架，内部封装了 JDBC，开发时只需要关注 sql 语句本身，不用去处理加载驱动，创建连接等过程</p><p>程序员可以直接编写原生 sql，可以严格控制 sql 执行性能，灵活度高</p><p>MyBatis 可以使用 xml 或注解来配置和映射原生信息，将 pojo 映射成数据库中的记录</p><h3 id="orm-是什么" tabindex="-1">ORM 是什么 <a class="header-anchor" href="#orm-是什么" aria-label="Permalink to &quot;ORM 是什么&quot;">​</a></h3><p>ORM，对象关系映射，是一种为了解决关系型数据库数据与简单 Java 对象的映射关系的技术</p><p>通过使用描述对象和数据库之间映射的元数据，将程序中的对象自动持久化到关系型数据库中</p><h3 id="为什么说-mybatis-是半自动-orm-映射工具-它与全自动的区别在哪里" tabindex="-1">为什么说 Mybatis 是半自动 ORM 映射工具？它与全自动的区别在哪里？ <a class="header-anchor" href="#为什么说-mybatis-是半自动-orm-映射工具-它与全自动的区别在哪里" aria-label="Permalink to &quot;为什么说 Mybatis 是半自动 ORM 映射工具？它与全自动的区别在哪里？&quot;">​</a></h3><p>Hibernate 属于全自动 ORM 映射工具，使用 Hibernate 查询关联对象或者关联集合对象时，可以根据对象关系模型直接获取</p><p>Mybatis 在查询关联对象或关联集合对象时，需要手动编写 SQL 来完成</p><h2 id="mybatis-使用过程" tabindex="-1">MyBatis 使用过程 <a class="header-anchor" href="#mybatis-使用过程" aria-label="Permalink to &quot;MyBatis 使用过程&quot;">​</a></h2><p><img src="https://cdn.domye.top/uploads/10/1761888962.webp" alt="" loading="lazy"></p><p><img src="https://cdn.domye.top/uploads/10/1761890228.webp" alt="" loading="lazy"></p><h3 id="创建-sqlsessionfactory" tabindex="-1">创建 SqlSessionFactory <a class="header-anchor" href="#创建-sqlsessionfactory" aria-label="Permalink to &quot;创建 SqlSessionFactory&quot;">​</a></h3><p>SqlSessionFactory 是 MyBatis 框架中的核心接口，它是创建 SqlSession 的工厂类，负责管理数据库会话的创建和配置</p><ol><li><strong>创建 SqlSession</strong>：作为工厂类，生产 SqlSession 实例</li><li><strong>管理数据库配置</strong>：持有 MyBatis 的所有配置信息</li><li><strong>线程安全</strong>：SqlSessionFactory 一旦创建，可以在应用运行期间一直存在</li></ol><h3 id="创建-sqlsession" tabindex="-1">创建 SqlSession <a class="header-anchor" href="#创建-sqlsession" aria-label="Permalink to &quot;创建 SqlSession&quot;">​</a></h3><p>SqlSession（会话）可以理解为程序和数据库之间的桥梁</p><h3 id="通过-sqlsession-执行数据库操作" tabindex="-1">通过 sqlsession 执行数据库操作 <a class="header-anchor" href="#通过-sqlsession-执行数据库操作" aria-label="Permalink to &quot;通过 sqlsession 执行数据库操作&quot;">​</a></h3><p>可以通过 SqlSession 实例来直接执行已映射的 SQL 语句：</p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Blog blog </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Blog)session.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">selectOne</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;org.mybatis.example.BlogMapper.selectBlog&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">101</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>更常用的方式是先获取 Mapper(映射)，然后再执行 SQL 语句：</p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BlogMapper mapper </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> session.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getMapper</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(BlogMapper.class);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Blog blog </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mapper.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">selectBlog</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">101</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果是更新、删除语句，我们还需要提交一下事务。</p><p>最后一定要调用 session.close()关闭会话</p><h2 id="和-的区别" tabindex="-1">#{}和${}的区别? <a class="header-anchor" href="#和-的区别" aria-label="Permalink to &quot;#{}和${}的区别?&quot;">​</a></h2><p><code>#{}</code> 是预编译处理，<code>${}</code> 是字符串替换</p><p>当使用 <code>#{}</code> 时，MyBatis 会在 SQL 执行之前，将占位符替换为问号 <code>?</code>，并使用参数值来替代这些问号</p><p>当使用 <code>${}</code> 时，参数的值会直接替换到 SQL 语句中去，而不会经过预处理</p><h2 id="mybatis-的一级、二级缓存" tabindex="-1">Mybatis 的一级、二级缓存 <a class="header-anchor" href="#mybatis-的一级、二级缓存" aria-label="Permalink to &quot;Mybatis 的一级、二级缓存&quot;">​</a></h2><ul><li>一级缓存: 基于 PerpetualCache 的 HashMap 本地缓存，其存储作用域为 SqlSession，各个 SqlSession 之间的缓存相互隔离，当 Session flush 或 close 之后，该 SqlSession 中的所有 Cache 就将清空，MyBatis 默认打开一级缓存</li><li>二级缓存与一级缓存其机制相同，默认也是采用 PerpetualCache，HashMap 存储，不同之处在于其存储作用域为 Mapper(Namespace)，可以在多个 SqlSession 之间共享，并且可自定义存储源，如 Ehcache。默认不打开二级缓存，要开启二级缓存，使用二级缓存属性类需要实现 Serializable 序列化接口(可用来保存对象的状态),可在它的映射文件中配置</li></ul><h2 id="如何防止-sql-住入" tabindex="-1">如何防止 sql 住入 <a class="header-anchor" href="#如何防止-sql-住入" aria-label="Permalink to &quot;如何防止 sql 住入&quot;">​</a></h2><h3 id="使用参数化查询" tabindex="-1">使用参数化查询 <a class="header-anchor" href="#使用参数化查询" aria-label="Permalink to &quot;使用参数化查询&quot;">​</a></h3><p>使用参数化查询，即使用<code>PreparedStatement</code>对象，通过<code>setXxx</code>方法设置参数值，而不是通过字符串拼接 SQL 语句。这样可以有效防止 SQL 注入</p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">String query </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;SELECT * FROM users WHERE username = ?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PreparedStatement pstmt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> connection.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">prepareStatement</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(query);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pstmt.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setString</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, userName);  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// userName 是用户输入</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ResultSet rs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pstmt.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">executeQuery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="限制用户输入" tabindex="-1">限制用户输入 <a class="header-anchor" href="#限制用户输入" aria-label="Permalink to &quot;限制用户输入&quot;">​</a></h3><p>对用户输入进行验证和过滤，只允许输入预期的数据，不允许输入特殊字符或 SQL 关键字</p><h3 id="使用-orm-框架" tabindex="-1">使用 ORM 框架 <a class="header-anchor" href="#使用-orm-框架" aria-label="Permalink to &quot;使用 ORM 框架&quot;">​</a></h3><p>在 MyBatis 中，使用<code>#{}</code>占位符来代替直接拼接 SQL 语句，MyBatis 会自动进行参数化处理</p>',41)]))}const y=a(t,[["render",n]]);export{c as __pageData,y as default};
